341:     (input_memory_format  == at::MemoryFormat::ChannelsLast3d) ||
342:     (weight_memory_format == at::MemoryFormat::ChannelsLast3d)
343:   );
344:   if (can_use_cudnn_channels_last_3d) {
345:     return at::MemoryFormat::ChannelsLast3d;
346:   }
347: 
