610:     auto bias_c = bias.contiguous();
611:     auto rmean_c = running_mean.defined() ? running_mean.contiguous() : running_mean;
612:     auto rvar_c = running_var.defined() ? running_var.contiguous() : running_var;
613: 
614:     auto [output, save_mean, save_var, reserve] =
615:         at::cudnn_batch_norm(input_c, weight_c, bias_c, rmean_c, rvar_c,
616:                              training, momentum, eps);
617: 
618:     return std::tuple<Tensor, Tensor, Tensor, Tensor, int64_t>(
619:         output, save_mean, save_var, reserve, 1);
620:   }
621: 
622:   Tensor reserve = at::empty({0}, input.options().dtype(kByte));
623: 
624:   if (backend == BatchNormBackend::Miopen) {
625:     return std::tuple_cat(
626:              at::miopen_batch_norm(
627:                input.contiguous(), weight.contiguous(), bias.contiguous(),
628:                running_mean.defined() ? running_mean.contiguous() : running_mean,
629:                running_var.defined() ? running_var.contiguous() : running_var,
630:                training, momentum, eps),
631:              std::tuple<Tensor>(reserve),
632:              std::make_tuple(2));
633:   }
634: 
635:   return std::tuple_cat(
636:            at::native_batch_norm(
637:              input, weight, bias, running_mean, running_var, training, momentum, eps),
638:            std::tuple<Tensor>(reserve),
639:            std::make_tuple(0));
640: }
