642: std::tuple<Tensor, Tensor, Tensor> _batch_norm_impl_index_backward(
643:     int64_t impl_index,
644:     const Tensor& input, const Tensor& grad_output, const std::optional<Tensor>& weight_opt /* optional */, const std::optional<Tensor>& running_mean_opt /* optional */, const std::optional<Tensor>& running_var_opt /* optional */, const std::optional<Tensor>& save_mean_opt /* optional */, const std::optional<Tensor>& save_var_transform_opt /* optional */,
645:     bool train, double epsilon, std::array<bool, 3> output_mask, const Tensor &reservedSpace) {
646:   // See [Note: hacky wrapper removal for optional tensor]
647:   c10::MaybeOwned<Tensor> weight_maybe_owned = at::borrow_from_optional_tensor(weight_opt);
648:   const Tensor& weight = *weight_maybe_owned;
649:   const Tensor& running_mean = running_mean_opt.value_or(Tensor());
650:   const Tensor& running_var = running_var_opt.value_or(Tensor());
651:   const Tensor& save_mean = save_mean_opt.value_or(Tensor());
652:   const Tensor& save_var_transform = save_var_transform_opt.value_or(Tensor());
653: 
654:   if (input.numel() == 0) {
655:     std::vector<int64_t> dims(input.dim() - 1);
656:     dims[0] = 0;
657:     std::iota(dims.begin() + 1, dims.end(), 2);
658: 
659:     // don't return empty tensor because it will break gradient chain
660:     Tensor grad_input;
661:     Tensor grad_weight;
662:     Tensor grad_bias;
663:     if (output_mask[2]) {
664:       grad_bias = grad_output.sum(dims);
665:     }
666:     if (output_mask[1]) {
667:       grad_weight = (grad_output * input).sum(dims);
668:     }
669:     if (output_mask[0] && weight.defined()) {
670:       grad_input = grad_output * weight[0];
671:     }
672:     return std::make_tuple(grad_input, grad_weight, grad_bias);
673:   }
674: 
675:   // backward in inference mode is not supported in cudnn, fallback to native
676:   if (impl_index == 0 || (!train)) {
677:     return at::native_batch_norm_backward(grad_output, input, weight, running_mean, running_var, save_mean, save_var_transform, train, epsilon, output_mask);
678:   } else if (impl_index == 1) {
679:     // TODO: _batch_norm_impl_index_backward is only used in JIT. cudnn NHWC
680:     // format conversion is done inside cudnn_batch_norm_backward instead
681:     return at::cudnn_batch_norm_backward(input, grad_output, weight, running_mean, running_var, save_mean, save_var_transform, epsilon, reservedSpace);
682:   } else if (impl_index == 2) {
683:     return at::miopen_batch_norm_backward(input, grad_output, weight, running_mean, running_var, save_mean, save_var_transform, epsilon);
684:   }
685:   TORCH_INTERNAL_ASSERT(false, "Unsupported impl_index in _batch_norm_impl_index_backward: ", impl_index);
686: }
