782: std::tuple<Tensor&, Tensor&, Tensor&> batch_norm_cpu_out(const Tensor& self, const std::optional<Tensor>& weight_opt, const std::optional<Tensor>& bias_opt, const std::optional<Tensor>& running_mean_opt, const std::optional<Tensor>& running_var_opt,
783:                                                   bool train, double momentum, double eps, Tensor& out, Tensor& save_mean, Tensor& save_var) {
784:   const bool has_running_mean = (running_mean_opt.has_value() && running_mean_opt->defined());
785:   const bool has_running_var = (running_var_opt.has_value() && running_var_opt->defined());
786:   TORCH_CHECK_VALUE(has_running_mean == has_running_var,
