789:   // See [Note: hacky wrapper removal for optional tensor]
790:   c10::MaybeOwned<Tensor> weight_maybe_owned = at::borrow_from_optional_tensor(weight_opt);
791:   const Tensor& weight = *weight_maybe_owned;
792:   const Tensor& bias = bias_opt.value_or(Tensor());
793:   const Tensor& running_mean = running_mean_opt.value_or(Tensor());
794:   const Tensor& running_var = running_var_opt.value_or(Tensor());
795: 
796:   checkBackend("batch_norm_cpu_out", {self, weight, bias, running_mean, running_var}, Backend::CPU);
797:   // Resize out
798:   at::native::resize_output(out, self.sizes());
799: 
800:   const bool mixed_type = is_mixed_type(self, weight, bias, running_mean, running_var);
801:   AT_DISPATCH_FLOATING_TYPES_AND2(ScalarType::BFloat16, ScalarType::Half, self.scalar_type(), "batch_norm", [&] {
802:     using opmath_t = at::opmath_type<scalar_t>;
803:     if (mixed_type) {
804:       check_mixed_data_type(self, weight, bias, running_mean, running_var);
805:       if (!train) {
806:         return batch_norm_cpu_transform_input_template<scalar_t, opmath_t>(self, weight, bias, save_mean, save_var, running_mean, running_var, train, eps, out);
807:       } else {
808:         // Resize save_mean and save_var
809:         at::native::resize_output(save_mean, {self.size(1)});
810:         at::native::resize_output(save_var, {self.size(1)});
811:         auto save_stats = batch_norm_cpu_update_stats_template<scalar_t, opmath_t, InvStd>(self, running_mean, running_var, momentum, eps, save_mean, save_var);
812:         return batch_norm_cpu_transform_input_template<scalar_t, opmath_t>(self, weight, bias, std::get<0>(save_stats), std::get<1>(save_stats), running_mean, running_var, train, eps, out);
813:       }
814:     } else {
815:       if (!train) {
816:         return batch_norm_cpu_transform_input_template<scalar_t, scalar_t>(self, weight, bias, save_mean, save_var, running_mean, running_var, train, eps, out);
817:       } else {
818:         // Resize save_mean and save_var
819:         at::native::resize_output(save_mean, {self.size(1)});
820:         at::native::resize_output(save_var, {self.size(1)});
821:         auto save_stats = batch_norm_cpu_update_stats_template<scalar_t, scalar_t, InvStd>(self, running_mean, running_var, momentum, eps, save_mean, save_var);
822:         return batch_norm_cpu_transform_input_template<scalar_t, scalar_t>(self, weight, bias, std::get<0>(save_stats), std::get<1>(save_stats), running_mean, running_var, train, eps, out);
823:       }
824:     }
825:   });
826: 
827:   return std::tuple<Tensor& ,Tensor&, Tensor&>(out, save_mean, save_var);
